B.IX=new A.az("Following the gear malfunction, the captain decided to abort the landing.","\u0130ni\u015f tak\u0131m\u0131 ar\u0131zas\u0131n\u0131n ard\u0131ndan kaptan ini\u015fi iptal etmeye karar verdi.","abort")
B.Uy=s([B.Jg,B.JA,B.IX],t.l)
B.N3=new A.K(B.a9,"Emergency Communication",null,B.Uy,null,null)
B.OV=new A.K(B.aa,"\u2708\ufe0f Exam Tip",'"Incident" vs. "Accident" is a common exam question:\n\u2022 **Incident**: something happened but no one died and no major damage occurred\n\u2022 **Accident**: death, serious injury, OR substantial damage occurred\n\n"Distress" vs. "Urgency":\n\u2022 **Distress (MAYDAY)**: needs help NOW \u2014 immediate danger to life\n\u2022 **Urgency (PAN-PAN)**: serious concern, but not an immediate threat to life',null,null,null)
