B.Ox=new A.K(B.aa,"\u2708\ufe0f Exam Tip",'Key reporting verbs and their prepositions:\n\u2022 said (that) \u2014 general statement\n\u2022 told + person + (that) \u2014 "told him/her"\n\u2022 reported (that) \u2014 formal/written report\n\u2022 informed + person + (that) \u2014 official notification\n\u2022 warned + person + (that/about) \u2014 hazard warning\n\nNo preposition after "said": \u2713 "said **that**" / \u2717 "said **to** him that"',null,null,null)
