B.NO=new A.K(B.a8,"Articles signal definiteness and context",'While articles seem simple, they are among the most frequently tested grammar points in aviation English because technical documents, manuals, and ATC communications all follow specific article usage patterns.\n\nA wrong article changes the meaning: "**a** hydraulic pump" (any one) vs. "**the** hydraulic pump" (a specific one we are discussing).',null,null,null)
B.K7=new A.nt(5,"articleUsage")
