B.Nc=new A.K(B.B,"\ud83d\udd25 Engine Failure Vocabulary","**Thrust lever** \u2014 controls engine power (throttle)\n**Fuel control lever** \u2014 starts/stops fuel to engine\n**Engine fire handle** \u2014 emergency shut-off and fire suppression control\n**HP fuel cock / Shutoff valve** \u2014 high-pressure fuel control\n**N1 / N2** \u2014 fan speed (%) / core speed (%)\n**EGT** \u2014 Exhaust Gas Temperature\n**ITT** \u2014 Interstage Turbine Temperature\n**Surge** \u2014 compressor stall; loud bang, rpm fluctuation",null,null,null)
B.NG=new A.K(B.B,"\ud83d\udccb Checklist Action Patterns",'Engine failure checklist sequence uses these exact phrases:\n\n"Engine fire, failure or severe damage \u2014 **ECAM ACTIONS**... **PERFORM**"\n"Thrust lever \u2014 **IDLE**"\n"If engine does not recover \u2014 engine **MASTER switch** \u2014 **OFF**"\n"Engine fire pushbutton \u2014 **PUSH**"\n"If fire not extinguished \u2014 **DISCHARGE** second agent"\n"Land at nearest suitable aerodrome \u2014 **CONSIDER**"\n\nKey pattern verbs: **idle, push, pull, discharge, confirm, verify, cross-check**',null,null,null)
B.Jl=new A.az("In the event of an engine fire, the crew must pull the engine fire handle.","Motor yang\u0131n\u0131 durumunda ekip, motor yang\u0131n kolunu \xe7ekmelidir.","pull the engine fire handle")
B.JC=new A.az("If the fire is not extinguished, discharge the second fire extinguisher agent.","Yang\u0131n s\xf6nd\xfcr\xfclemezse ikinci s\xf6nd\xfcr\xfcc\xfc maddesini de\u015farj edin.","discharge")
B.JJ=new A.az("Cross-check the affected engine number before taking any action.","Herhangi bir i\u015flem yapmadan \xf6nce etkilenen motor numaras\u0131n\u0131 \xe7apraz kontrol edin.","Cross-check")
