B.a_I=new A.a5(-272,B.ar,642,'"Expect vectors" on a STAR means:',B.UW,1,B.aU,null,null,null)
B.Rp=s(["Climb to speed 220 knots","Maintain 220 KIAS or less","Set Mach 0.220","Not exceed 220 feet per minute climb"],t.s)
