B.Mk=new A.ci("reading_5","SID/STAR Procedures","\ud83d\uddfa\ufe0f",B.Rj)
B.Oh=new A.K(B.a8,"Accident reports are complex texts","Aviation accident investigation reports (such as those produced by ICAO Annex 13 standards) are among the most complex texts tested in aviation English exams.\n\nThey contain technical terminology, passive constructions, reported speech, and conditional reasoning \u2014 all combined in a single document.",null,null,null)
B.OZ=new A.K(B.B,"\ud83d\udccb Report Structure","A standard accident report contains:\n1. **Synopsis** \u2014 brief summary of the accident\n2. **Factual information** \u2014 aircraft, crew, weather, airport data\n3. **Analysis** \u2014 what happened and why (cause chain)\n4. **Findings** \u2014 established facts\n5. **Cause** \u2014 probable cause(s)\n6. **Safety recommendations** \u2014 what should change\n\nExam questions usually target **Factual Information** and **Analysis** sections.",null,null,null)
B.P1=new A.K(B.B,"\ud83d\udd0d Critical Reading Skills","For accident report passages:\n\u2022 **Sequence words**: prior to, during, following, subsequently, as a result\n\u2022 **Causal language**: due to, caused by, attributed to, led to, resulted in\n\u2022 **Finding vs. Recommendation**: findings are facts; recommendations are suggestions\n\u2022 **Contributing factor** \u2260 **Probable cause**: contributing factors worsen the situation; probable cause is the primary reason",null,null,null)
B.II=new A.az("The accident was attributed to the crew's failure to monitor fuel quantity during the extended hold.","Kaza, ekibin uzun s\xfcren bekleme s\u0131ras\u0131nda yak\u0131t miktar\u0131n\u0131 izlememesine ba\u011fland\u0131.","attributed to")
B.Jd=new A.az("A contributing factor was the inadequate crew resource management training.","Katk\u0131da bulunan bir fakt\xf6r yetersiz ekip kaynak y\xf6netimi e\u011fitimiydi.","contributing factor")
B.QW=s([B.II,B.Jd],t.l)
B.Nh=new A.K(B.a9,"Report Language Examples",null,B.QW,null,null)
B.NI=new A.K(B.aa,"\u2708\ufe0f Advanced Reading Strategy","The 3-read method for complex passages:\n1. **First read**: skim for topic and structure (30 seconds)\n2. **Read question**: understand exactly what is asked\n3. **Second read**: focus on the relevant paragraph only\n\nNever answer from memory \u2014 always verify in the text. Advanced questions often have **plausible but incorrect** distractors that use words from the passage in the wrong context.",null,null,null)
B.R7=s(["To start the engine for the first time","To test the fuel system","To increase engine speed","To test the electrical system"],t.s)
B.a0F=new A.a5(-100,B.ar,606,"What is the purpose of wet motoring the engine?",B.R7,1,B.K,null,null,null)
B.QA=s(["Both are turned ON","One is ON and one is OFF","Both are turned OFF","The position does not matter"],t.s)
B.a06=new A.a5(-101,B.ar,607,"During wet motoring, what is the position of the ignition systems?",B.QA,2,B.K,null,null,null)
B.Sb=s(["Engine speed only","The starter motor temperature","The exhaust nozzle for signs of fuel","The HP rotor vibration"],t.s)
